import { task, streams, wait, logger } from "@trigger.dev/sdk";

const trial_id = "cancellable_ai_stream__kcWqQS4";

// Define an output stream for AI-generated text chunks
const aiStream = streams.define<string>({ id: `aiStream-${trial_id}` });

// Define an input stream for cancellation signals
const cancelStream = streams.input<{ reason?: string }>({ id: `cancelStream-${trial_id}` });

export const aiTask = task({
  id: `aiTask-${trial_id}`,
  run: async (payload: { prompt?: string }) => {
    logger.info("aiTask started", { trialId: trial_id, prompt: payload.prompt });

    let cancelled = false;
    let cancelReason: string | undefined;

    // Register a listener on the cancel input stream
    const subscription = cancelStream.on((data) => {
      logger.info("Cancellation received", { reason: data.reason });
      cancelled = true;
      cancelReason = data.reason;
    });

    try {
      // Simulate AI generation: append 10 chunks with 1-second delays
      for (let i = 1; i <= 10; i++) {
        if (cancelled) {
          logger.info("Generation aborted due to cancellation", {
            reason: cancelReason,
            chunksProduced: i - 1,
          });
          break;
        }

        const chunk = `chunk-${i}: Simulated AI output token ${i} `;
        await aiStream.append(chunk);
        logger.info("Appended chunk", { chunk, index: i });

        // Wait 1 second before the next chunk (skips the delay after the last chunk)
        if (i < 10) {
          await wait.for({ seconds: 1 });
        }
      }
    } finally {
      // Clean up the cancel stream subscription
      subscription.off();
    }

    if (cancelled) {
      return {
        status: "cancelled",
        reason: cancelReason,
      };
    }

    return {
      status: "completed",
      message: "All 10 chunks generated successfully",
    };
  },
});
